const obs = new Observable(subscriber => {
  console.log('executing');     // only prints on subscribe
  subscriber.next(1);
  subscriber.next(2);           // can emit multiple values
  subscriber.complete();
});
obs.subscribe(val => console.log(val)); // 1, 2
```

**TL;DR:** Promise = single future value, eager. Observable = lazy stream of values with cancellation and powerful operators.

